export function Footer({ data }: FooterProps) {
  const socialTitle = data?.socialTitle || "تابعنا على وسائل التواصل";
  const socialLinks = data?.socialLinks || [
    { platform: "instagram", url: "#" },
    { platform: "twitter", url: "#" },
    { platform: "snapchat", url: "#" },
    { platform: "tiktok", url: "#" },
    { platform: "facebook", url: "#" },
  ];
  const locationTitle = data?.locationTitle || "الموقع";
  const location = data?.location || "الرياض، حي المهدية";
  const contactTitle = data?.contactTitle || "تواصل معنا";
  const email = data?.email || "info@codeclouders.com";
  const phone = data?.phone || "0501479944";
  const linksTitle = data?.linksTitle || "روابط سريعة";
  const links = data?.links || [
    { label: "الرئيسية", url: "/" },
    { label: "مشاريعنا", url: "/work" },
    { label: "خدماتنا", url: "/services" },
    { label: "لماذا حي المهدية", url: "#why-us" },
    { label: "تواصل معنا", url: "/contact" },
  ];
  const copyright =
    data?.copyright || "جميع الحقوق محفوظة© 2026 - Code Clouders..";

  return (
    <footer
      className={cn(
        "bg-[#0E1730]",
        "py-10 md:py-16",
        "text-white",
        "w-full",
        "relative",
      )}
      id="contact"
    >
      <div
        className={cn(
          "mx-auto",
          "max-w-[1240px]",
          "px-4 sm:px-5",
          "lg:px-0",
          "flex",
          "flex-col",
          "gap-8 md:gap-10",
          "items-stretch",
        )}
      >
        {/* Upper Footer Container */}
        <div
          className={cn(
            "grid",
            "grid-cols-2",
            "lg:flex",
            "lg:flex-row",
            "gap-8 md:gap-12",
            "lg:gap-[134px]",
            "items-start",
            "justify-between",
            "w-full",
          )}
        >
          {/* Column 1 (Logo): Centered full-width at the top on mobile, start-aligned on desktop */}
          <div className={cn("col-span-2 flex justify-center mb-2 lg:mb-0 lg:col-span-1 lg:justify-start lg:w-[160px] h-[39px] relative shrink-0 w-full")}>
            <div className="w-[160px] h-full relative">
              <Link href="/">
                <img
                  src="/assets/footer-logo.svg"
                  alt="Code Clouders"
                  className={cn(
                    "absolute",
                    "block",
                    "inset-0",
                    "max-w-none",
                    "size-full",
                    "cursor-pointer"
                  )}
                  loading="lazy"
                />
              </Link>
            </div>
          </div>

          {/* Column 2 (Quick Links): Side-by-side on mobile, start-aligned on mobile, end-aligned on desktop */}
          <div
            className={cn(
              "flex",
              "flex-col",
              "gap-4",
              "col-span-1",
              "items-start",
              "lg:items-end",
              "lg:rtl:items-start",
              "lg:ltr:items-end",
              "flex-1",
            )}
          >
            <p
              className={cn(
                "font-serif-display",
                "font-medium",
                "text-[20px]",
                "text-white",
                "leading-none",
              )}
            >
              {linksTitle}
            </p>
            <div
              className={cn(
                "flex",
                "flex-col",
                "gap-2",
                "items-start",
                "lg:items-end",
                "lg:rtl:items-start",
                "lg:ltr:items-end",
                "text-[16px]",
                "text-white/70",
              )}
            >
              {links.map((link) => {
                const isHash = link.url.startsWith('#') || link.url.startsWith('http') || link.url.startsWith('mailto') || link.url.startsWith('tel')
                return isHash ? (
                  <a
                    key={`${link.url}-${link.label}`}
                    href={link.url}
                    className={cn(
                      "hover:text-white",
                      "transition-colors",
                      "duration-200",
                    )}
                  >
                    {link.label}
                  </a>
                ) : (
                  <Link
                    key={`${link.url}-${link.label}`}
                    href={link.url}
                    className={cn(
                      "hover:text-white",
                      "transition-colors",
                      "duration-200",
                    )}
                  >
                    {link.label}
                  </Link>
                );
              })}
            </div>
          </div>

          {/* Column 3 (Location and Contact): Side-by-side on mobile, start-aligned on mobile, end-aligned on desktop */}
          <div
            className={cn(
              "flex",
              "flex-col",
              "gap-8",
              "col-span-1",
              "items-start",
              "lg:items-end",
              "lg:rtl:items-start",
              "lg:ltr:items-end",
              "flex-1",
            )}
          >
            {/* Location Sub-column */}
            <div
              className={cn(
                "flex",
                "flex-col",
                "gap-2",
                "items-start",
                "lg:items-end",
                "lg:rtl:items-start",
                "lg:ltr:items-end",
                "w-full",
              )}
            >
              <p
                className={cn(
                  "font-serif-display",
                  "font-medium",
                  "text-[20px]",
                  "text-white",
                  "leading-none",
                )}
              >
                {locationTitle}
              </p>
              <div
                className={cn(
                  "flex",
                  "flex-row",
                  "items-center",
                  "gap-2",
                  "text-[16px]",
                  "text-white/70",
                  "justify-start",
                  "lg:rtl:justify-start",
                  "lg:ltr:justify-end",
                )}
              >
                <LocationIcon />
                <span>{location}</span>
              </div>
            </div>
            {/* Contact Sub-column */}
            <div
              className={cn(
                "flex",
                "flex-col",
                "gap-2",
                "items-start",
                "lg:items-end",
                "lg:rtl:items-start",
                "lg:ltr:items-end",
                "w-full",
              )}
            >
              <p
                className={cn(
                  "font-serif-display",
                  "font-medium",
                  "text-[20px]",
                  "text-white",
                  "leading-none",
                )}
              >
                {contactTitle}
              </p>
              <div
                className={cn(
                  "flex",
                  "flex-col",
                  "gap-2",
                  "items-start",
                  "lg:items-end",
                  "lg:rtl:items-start",
                  "lg:ltr:items-end",
                  "text-[16px]",
                  "text-white/70",
                  "w-full",
                )}
              >
                <a
                  href={`mailto:${email}`}
                  className={cn(
                    "flex",
                    "flex-row",
                    "items-center",
                    "gap-2",
                    "hover:text-white",
                    "transition-colors",
                    "duration-200",
                    "justify-start",
                    "lg:rtl:justify-start",
                    "lg:ltr:justify-end",
                  )}
                >
                  <InboxIcon />
                  <span className={cn("dir-ltr", "select-all")}>{email}</span>
                </a>
                <a
                  href={`tel:${phone}`}
                  className={cn(
                    "flex",
                    "flex-row",
                    "items-center",
                    "gap-2",
                    "hover:text-white",
                    "transition-colors",
                    "duration-200",
                    "justify-start",
                    "lg:rtl:justify-start",
                    "lg:ltr:justify-end",
                  )}
                >
                  <CallIcon />
                  <span className={cn("dir-ltr", "select-all")}>{phone}</span>
                </a>
              </div>
            </div>
          </div>

          {/* Column 4 (Social Media): Centered full-width at the bottom on mobile, end-aligned on desktop */}
          <div
            className={cn(
              "flex",
              "flex-col",
              "gap-4",
              "col-span-2",
              "lg:col-span-1",
              "items-center",
              "lg:items-end",
              "lg:rtl:items-start",
              "lg:ltr:items-end",
              "shrink-0",
            )}
          >
            <p
              className={cn(
                "font-serif-display",
                "font-medium",
                "text-[20px]",
                "text-white",
                "leading-none",
              )}
            >
              {socialTitle}
            </p>
            <div
              className={cn(
                "flex",
                "flex-row",
                "gap-4",
                "items-center",
                "justify-center",
                "lg:justify-start",
                "lg:rtl:justify-start",
                "lg:ltr:justify-end",
                "w-full",
              )}
            >
              {socialLinks.map((social) => {
                const IconComponent =
                  SOCIAL_ICONS[social.platform.toLowerCase()];
                if (!IconComponent) return null;
                return (
                  <a
                    key={social.platform + "-" + social.url}
                    href={social.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    aria-label={social.platform}
                    className={cn(
                      "w-6",
                      "h-6",
                      "rounded-full",
                      "bg-white",
                      "flex",
                      "items-center",
                      "justify-center",
                      "text-[#0E1730]",
                      "hover:opacity-85",
                      "transition-all",
                      "duration-200",
                      "hover:scale-105",
                    )}
                  >
                    <IconComponent />
                  </a>
                );
              })}
            </div>
          </div>
        </div>

        {/* Divider & Copyright */}
        <div
          className={cn(
            "w-full",
            "pt-8",
            "border-t",
            "border-white/10",
            "flex",
            "justify-center",
          )}
        >
          <p
            className={cn(
              "font-serif-display",
              "font-bold",
              "text-[12px]",
              "text-[#D5D6D7]",
              "text-center",
              "leading-normal",
            )}
          >
            {copyright}
          </p>
        </div>
      </div>
    </footer>
  );
}
